using UniversityCourseCatalog.Models;

namespace UniversityCourseCatalog.Services;

public class CatalogService
{
    private readonly List<Department> _departments =
    [
        new() { Id = 1, Name = "Computer Science", Abbreviation = "CS" },
        new() { Id = 2, Name = "Mathematics", Abbreviation = "MATH" },
        new() { Id = 3, Name = "English", Abbreviation = "ENG" },
        new() { Id = 4, Name = "Physics", Abbreviation = "PHYS" },
        new() { Id = 5, Name = "History", Abbreviation = "HIST" }
    ];

    private readonly List<Course> _courses =
    [
        new()
        {
            Id = 1, CourseCode = "CS 101", Title = "Introduction to Programming",
            Description = "An introductory course covering fundamental programming concepts using Python. Students will learn variables, control flow, functions, and basic data structures.",
            Credits = 3, Schedule = "Mon/Wed/Fri 9:00–9:50 AM", DepartmentId = 1, IsFeatured = true,
            InstructorName = "Dr. Sarah Chen",
            InstructorBio = "Dr. Chen holds a PhD in Computer Science from MIT and has 15 years of teaching experience. Her research focuses on programming language design and CS education."
        },
        new()
        {
            Id = 2, CourseCode = "CS 201", Title = "Data Structures and Algorithms",
            Description = "Study of fundamental data structures (lists, trees, graphs, hash tables) and algorithm design techniques (divide and conquer, dynamic programming, greedy algorithms).",
            Credits = 4, Schedule = "Tue/Thu 10:30 AM–12:00 PM", DepartmentId = 1, IsFeatured = true,
            InstructorName = "Dr. James Okafor",
            InstructorBio = "Dr. Okafor is an Associate Professor specializing in algorithm optimization. He previously worked at Google Research and has published over 40 papers."
        },
        new()
        {
            Id = 3, CourseCode = "CS 310", Title = "Database Systems",
            Description = "Covers relational database design, SQL, normalization, transaction processing, and an introduction to NoSQL databases.",
            Credits = 3, Schedule = "Mon/Wed 2:00–3:20 PM", DepartmentId = 1, IsFeatured = false,
            InstructorName = "Prof. Maria Gonzalez",
            InstructorBio = "Prof. Gonzalez spent a decade at Oracle before transitioning to academia. She brings real-world database engineering expertise to the classroom."
        },
        new()
        {
            Id = 4, CourseCode = "MATH 151", Title = "Calculus I",
            Description = "Limits, derivatives, and integrals of single-variable functions with applications to physics, engineering, and economics.",
            Credits = 4, Schedule = "Mon/Wed/Fri 11:00–11:50 AM", DepartmentId = 2, IsFeatured = true,
            InstructorName = "Dr. Robert Kim",
            InstructorBio = "Dr. Kim is a professor of mathematics with expertise in analysis and applied mathematics. He has received multiple teaching excellence awards."
        },
        new()
        {
            Id = 5, CourseCode = "MATH 250", Title = "Linear Algebra",
            Description = "Vector spaces, linear transformations, matrices, determinants, eigenvalues and eigenvectors, with applications.",
            Credits = 3, Schedule = "Tue/Thu 1:00–2:20 PM", DepartmentId = 2, IsFeatured = false,
            InstructorName = "Dr. Anika Patel",
            InstructorBio = "Dr. Patel's research spans algebraic geometry and computational mathematics. She is known for making abstract concepts accessible."
        },
        new()
        {
            Id = 6, CourseCode = "ENG 101", Title = "College Composition",
            Description = "Develops critical reading and writing skills. Students produce analytical essays, research papers, and creative works.",
            Credits = 3, Schedule = "Mon/Wed/Fri 10:00–10:50 AM", DepartmentId = 3, IsFeatured = false,
            InstructorName = "Prof. David Nguyen",
            InstructorBio = "Prof. Nguyen is a published author and composition specialist who brings creative writing techniques into academic writing instruction."
        },
        new()
        {
            Id = 7, CourseCode = "ENG 220", Title = "American Literature",
            Description = "A survey of American literary works from the colonial period to the present, examining themes of identity, democracy, and social change.",
            Credits = 3, Schedule = "Tue/Thu 9:00–10:20 AM", DepartmentId = 3, IsFeatured = true,
            InstructorName = "Dr. Lisa Monroe",
            InstructorBio = "Dr. Monroe is a specialist in 20th-century American fiction. Her book on the Harlem Renaissance was a finalist for the National Book Critics Circle Award."
        },
        new()
        {
            Id = 8, CourseCode = "PHYS 201", Title = "General Physics I",
            Description = "Mechanics, thermodynamics, and waves. Includes laboratory sessions with hands-on experiments.",
            Credits = 4, Schedule = "Mon/Wed 9:00–10:20 AM, Fri Lab 2:00–4:50 PM", DepartmentId = 4, IsFeatured = false,
            InstructorName = "Dr. Thomas Eriksson",
            InstructorBio = "Dr. Eriksson is an experimental physicist whose research on quantum optics has been featured in Nature and Physical Review Letters."
        },
        new()
        {
            Id = 9, CourseCode = "PHYS 305", Title = "Quantum Mechanics",
            Description = "Introduction to quantum theory: wave functions, Schrödinger equation, angular momentum, spin, and applications to atomic physics.",
            Credits = 3, Schedule = "Tue/Thu 2:00–3:20 PM", DepartmentId = 4, IsFeatured = false,
            InstructorName = "Dr. Thomas Eriksson",
            InstructorBio = "Dr. Eriksson is an experimental physicist whose research on quantum optics has been featured in Nature and Physical Review Letters."
        },
        new()
        {
            Id = 10, CourseCode = "HIST 110", Title = "World Civilizations",
            Description = "A global survey from ancient civilizations through the early modern period, exploring cultural, political, and economic developments.",
            Credits = 3, Schedule = "Mon/Wed/Fri 1:00–1:50 PM", DepartmentId = 5, IsFeatured = false,
            InstructorName = "Dr. Fatima Al-Rashid",
            InstructorBio = "Dr. Al-Rashid is a historian of the medieval Islamic world with a joint appointment in Middle Eastern Studies."
        }
    ];

    private readonly List<EnrollmentRequest> _enrollments = [];

    public List<Department> GetDepartments() => _departments;

    public Department? GetDepartment(int id) => _departments.FirstOrDefault(d => d.Id == id);

