@page "/"
@using UniversityCourseCatalog.Models
@using UniversityCourseCatalog.Services
@inject CatalogService CatalogService

<PageTitle>University Course Catalog</PageTitle>

<h1>University Course Catalog</h1>
<p class="lead">Welcome to the course catalog. Browse departments, explore courses, and submit enrollment requests.</p>

<h2>Featured Courses</h2>
<div class="row">
    @foreach (var course in _featuredCourses)
    {
        <div class="col-md-6 col-lg-4 mb-3">
            <div class="card h-100">
                <div class="card-body">
                    <h5 class="card-title">@course.CourseCode</h5>
                    <h6 class="card-subtitle mb-2 text-muted">@course.Title</h6>
                    <p class="card-text">@course.Credits credits &middot; @course.InstructorName</p>
                    <a href="/courses/@course.Id" class="btn btn-primary btn-sm">View Details</a>
                </div>
            </div>
        </div>
    }
</div>

<h2 class="mt-4">Departments</h2>
<div class="list-group">
    @foreach (var dept in _departments)
    {
        <a href="/courses?departmentId=@dept.Id" class="list-group-item list-group-item-action">
            <strong>@dept.Abbreviation</strong> &mdash; @dept.Name
        </a>
    }
</div>

@code {
    private List<Course> _featuredCourses = [];
    private List<Department> _departments = [];

