toolArgs.file_text:
@page "/courses/{Id:int}"
@using UniversityCourseCatalog.Models
@using UniversityCourseCatalog.Services
@inject CatalogService CatalogService

<PageTitle>@(_course?.Title ?? "Course Not Found")</PageTitle>

@if (_course is null)
{
    <h1>Course Not Found</h1>
    <p>The requested course does not exist.</p>
    <a href="/courses" class="btn btn-secondary">Back to Catalog</a>
}
else
{
    <nav aria-label="breadcrumb">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="/courses">Catalog</a></li>
            <li class="breadcrumb-item active">@_course.CourseCode</li>
        </ol>
    </nav>

    <h1>@_course.CourseCode &mdash; @_course.Title</h1>

    <div class="row mt-4">
        <div class="col-md-8">
            <h4>Description</h4>
            <p>@_course.Description</p>

            <h4>Schedule</h4>
            <p>@_course.Schedule</p>

            <h4>Credits</h4>
            <p>@_course.Credits</p>
        </div>
        <div class="col-md-4">
            <div class="card">
                <div class="card-body">
                    <h5 class="card-title">Instructor</h5>
                    <h6 class="card-subtitle mb-2 text-muted">@_course.InstructorName</h6>
                    <p class="card-text">@_course.InstructorBio</p>
                </div>
            </div>

            <a href="/enroll?courseId=@_course.Id" class="btn btn-success mt-3 w-100">Enroll in This Course</a>
        </div>
    </div>
}

@code {
    [Parameter] public int Id { get; set; }

    private Course? _course;

    protected override void OnInitialized()
    {
        _course = CatalogService.GetCourse(Id);
    }
}

@page "/enroll"
@using UniversityCourseCatalog.Models
@using UniversityCourseCatalog.Services
@inject CatalogService CatalogService
@rendermode InteractiveServer

<PageTitle>Enrollment Request</PageTitle>

<h1>Enrollment Request</h1>
<p>Fill out the form below to submit an enrollment request.</p>

@if (_submitted)
{
    <div class="alert alert-success">
        <h4>Request Submitted</h4>
        <p>Your enrollment request has been received. You will be notified once it is processed.</p>
        <a href="/courses" class="btn btn-primary">Back to Catalog</a>
    </div>
}
else
{
    <EditForm Model="_request" OnValidSubmit="HandleSubmit" FormName="enrollment" class="col-md-6">
        <DataAnnotationsValidator />
        <ValidationSummary class="text-danger" />

        <div class="mb-3">
            <label for="studentName" class="form-label">Full Name</label>
            <InputText id="studentName" class="form-control" @bind-Value="_request.StudentName" />
            <ValidationMessage For="() => _request.StudentName" class="text-danger" />
        </div>

        <div class="mb-3">
            <label for="studentId" class="form-label">Student ID</label>
            <InputText id="studentId" class="form-control" @bind-Value="_request.StudentId" />
            <ValidationMessage For="() => _request.StudentId" class="text-danger" />
        </div>

        <div class="mb-3">
            <label for="courseSelect" class="form-label">Course</label>
            <InputSelect id="courseSelect" class="form-select" @bind-Value="_request.CourseId">
                <option value="0">-- Select a course --</option>
                @foreach (var course in _courses)
                {
                    <option value="@course.Id">@course.CourseCode &mdash; @course.Title</option>
                }
            </InputSelect>
            <ValidationMessage For="() => _request.CourseId" class="text-danger" />
        </div>

        <button type="submit" class="btn btn-primary">Submit Enrollment Request</button>
    </EditForm>
}

@code {
    [SupplyParameterFromQuery] public int? CourseId { get; set; }

    private EnrollmentRequest _request = new();
    private List<Course> _courses = [];
    private bool _submitted;

    protected override void OnInitialized()
    {
        _courses = CatalogService.GetCourses();
        if (CourseId.HasValue)
            _request.CourseId = CourseId.Value;
    }

    private void HandleSubmit()
    {
        CatalogService.SubmitEnrollment(_request);
        _submitted = true;
    }
}
